package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class ErrorMessageTest {

    @Test
    fun testOffsetFieldErrorMessage() {
        // Reproduce the issue from the bug report
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val zone = TimeZone.of("America/New_York")
        val instant = Instant.parse("2023-01-15T10:30:00Z")

        // This should throw an error because we're only setting timeZoneId but the format
        // requires offset fields (offsetHours, offsetMinutesOfHour, offsetSecondsOfMinute)
        val exception = assertFailsWith<IllegalStateException> {
            readableFormat.format {
                setDateTime(instant.toLocalDateTime(zone))
                timeZoneId = zone.id
            }
        }

        // Verify the error message mentions the user-facing field name, not the internal name
        assertTrue(
            exception.message!!.contains("offsetHours"),
            "Error message should mention 'offsetHours', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("totalHoursAbs"),
            "Error message should not mention internal field name 'totalHoursAbs', but was: ${exception.message}"
        )
    }

    @Test
    fun testDateFieldErrorMessages() {
        // Test that date fields also have user-friendly error messages
        val format = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
        }

        // Try to format without setting required fields
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                year = 2023
                // monthNumber is missing
                dayOfMonth = 15
            }
        }

        // Verify the error message mentions the user-facing field name
        assertTrue(
            exception.message!!.contains("monthNumber"),
            "Error message should mention 'monthNumber', but was: ${exception.message}"
        )
    }

    @Test
    fun testTimeFieldErrorMessages() {
        // Test that time fields also have user-friendly error messages
        val format = DateTimeComponents.Format {
            hour()
            char(':')
            minute()
        }

        // Try to format without setting required fields
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                hour = 10
                // minute is missing
            }
        }

        // Verify the error message mentions the user-facing field name
        assertTrue(
            exception.message!!.contains("minute"),
            "Error message should mention 'minute', but was: ${exception.message}"
        )
    }

    @Test
    fun testDayOfWeekFieldErrorMessage() {
        // Test that dayOfWeek field has user-friendly error message (not isoDayOfWeek)
        val format = DateTimeComponents.Format {
            dayOfWeek(DayOfWeekNames.ENGLISH_FULL)
        }

        // Try to format without setting the field
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // dayOfWeek is missing
            }
        }

        // Verify the error message mentions the user-facing field name
        assertTrue(
            exception.message!!.contains("dayOfWeek"),
            "Error message should mention 'dayOfWeek', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("isoDayOfWeek"),
            "Error message should not mention internal field name 'isoDayOfWeek', but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetMinutesErrorMessage() {
        // Test that offsetMinutesOfHour has user-friendly error message
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        // Try to format with only hours set
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                // offsetMinutesOfHour is missing
            }
        }

        // Verify the error message mentions the user-facing field name
        assertTrue(
            exception.message!!.contains("offsetMinutesOfHour"),
            "Error message should mention 'offsetMinutesOfHour', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("minutesOfHour") && !exception.message!!.contains("offsetMinutesOfHour"),
            "Error message should not mention internal field name 'minutesOfHour' without 'offset' prefix, but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetSecondsErrorMessage() {
        // Test that offsetSecondsOfMinute has user-friendly error message
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            char(':')
            offsetSecondsOfMinute()
        }

        // Try to format without seconds
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                offsetMinutesOfHour = 30
                // offsetSecondsOfMinute is missing
            }
        }

        // Verify the error message mentions the user-facing field name
        assertTrue(
            exception.message!!.contains("offsetSecondsOfMinute"),
            "Error message should mention 'offsetSecondsOfMinute', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("secondsOfMinute") && !exception.message!!.contains("offsetSecondsOfMinute"),
            "Error message should not mention internal field name 'secondsOfMinute' without 'offset' prefix, but was: ${exception.message}"
        )
    }
}
"}

